  function saveReflection(id){
    const text = document.getElementById('reflectionText').value.trim();
    if(text){
      const prog = state.sessions[id];
      prog.reflections = prog.reflections || [];
      prog.reflections.push({ text, at:new Date().toISOString() });
      addXP(10);
      saveState();
    }
    renderMap();
  }

